# Category: datastore_security

import psycopg2

def install_extension(dbhost, dbport, dbname, dbuser, dbpassword, extension):
    try:
        conn = psycopg2.connect(
            host=dbhost,
            port=dbport,
            database=dbname,
            user=dbuser,
            password=dbpassword)
        
        cur = conn.cursor()
        
        create_ext_command = "CREATE EXTENSION IF NOT EXISTS {}".format(extension)
        cur.execute(create_ext_command)
        
        conn.commit()
        print("Extension {} installed successfully.".format(extension))
        
    except psycopg2.Error as e:
        print("Error occurred while installing extension {}: {}".format(extension, str(e)))
        
def enable_extension(dbhost, dbport, dbname, dbuser, dbpassword, extension):
    try:
        conn = psycopg2.connect(
            host=dbhost,
            port=dbport,
            database=dbname,
            user=dbuser,
            password=dbpassword)
        
        cur = conn.cursor()
        
        enable_ext_command = "ALTER SYSTEM SET shared_preload_wal_functions TO 'ON'; ALTER EXTENSION {} UPDATE USING INSTALL;".format(extension)
        cur.execute(enable_ext_command)
        
        conn.commit()
        print("Extension {} enabled successfully.".format(extension))
        
    except psycopg2.Error as e:
        print("Error occurred while enabling extension {}: {}".format(extension, str(e)))
        
def main():
    dbhost = input("Enter the database host: ")
